25	const PROCESSING_FEE = 5;
26	
27	const BASE_PREMIUMS: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  rune: 25,
33	  moonstone: 25,
34	};
35	
36	const INSURANCE_VALUES: Record<string, number> = {
37	  sword: 1000,
38	  amulet: 600,
39	  staff: 800,
40	  potion: 400,
41	  rune: 250,
42	  moonstone: 250,
43	};
44	
45	const DEDUCTIBLE = 100;
46	const CAP_MULTIPLIER = 2;
47	const PAYOUT_HIGH_ENCHANTMENT_THRESHOLD = 8;
48	const PAYOUT_HIGH_ENCHANTMENT_RATE = 0.5;
49	
50	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
51	
52	const BLOCK_SIZE = 3;
53	const BLOCK_PREMIUM = 60;
54	
55	const CURSE_SURCHARGE_RATE = 0.5;
56	const FIRST_INSURANCE_RATE = 0.1;
57	const HIGH_ENCHANTMENT_RATE = 0.3;
58	const HIGH_ENCHANTMENT_THRESHOLD = 5;
59	const LOYALTY_DISCOUNT_RATE = 0.2;
60	const LOYALTY_YEARS_THRESHOLD = 2;
61	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
62	
63	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
64	
65	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
66	
67	const groupKeyFor = (item: Item, index: number): string =>
68	  COMPONENT_TYPES.has(item.type) ? item.type : `item:${index}`;
69	
70	const groupItemsForPricing = (items: Item[]): Item[][] => {
71	  const groups = new Map<string, Item[]>();
72	  items.forEach((item, index) => {
73	    const key = groupKeyFor(item, index);
74	    const group = groups.get(key) ?? [];
75	    group.push(item);
76	    groups.set(key, group);
77	  });
78	  return [...groups.values()];
79	};
80	
81	const premiumForGroup = (group: Item[]): number =>
82	  group.length === BLOCK_SIZE
83	    ? BLOCK_PREMIUM
84	    : group.reduce((total, item) => total + basePremiumFor(item), 0);
85	
86	const totalBasePremiumFor = (items: Item[]): number =>
87	  groupItemsForPricing(items).reduce((total, group) => total + premiumForGroup(group), 0);
88	
89	const itemSurchargeFor = (
90	  items: Item[],
91	  qualifies: (item: Item) => boolean,
92	  rate: number,
93	): number =>
94	  items.reduce(
95	    (total, item) => (qualifies(item) ? total + basePremiumFor(item) * rate : total),
96	    0,
97	  );
98	
99	const isCursed = (item: Item): boolean => item.cursed === true;
100	
101	const isHighlyEnchanted = (item: Item): boolean =>
102	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
103	
104	type QuoteContext = { customer: Customer; quoteIndex: number };
105	
106	type PolicyModifier = (base: number, items: Item[], context: QuoteContext) => number;
107	
108	const discountWhen =
109	  (rate: number, qualifies: (context: QuoteContext) => boolean): PolicyModifier =>
110	  (base, _items, context) =>
111	    qualifies(context) ? -(base * rate) : 0;
112	
113	const isLoyalCustomer = ({ customer }: QuoteContext): boolean =>
114	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
115	
116	const isFollowUpQuote = ({ quoteIndex }: QuoteContext): boolean => quoteIndex > 0;
117	
118	const cursedSurcharge: PolicyModifier = (_base, items) =>
119	  itemSurchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
120	
121	const highEnchantmentSurcharge: PolicyModifier = (_base, items) =>
122	  itemSurchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE);
123	
124	const firstInsuranceSurcharge: PolicyModifier = (base) => base * FIRST_INSURANCE_RATE;
125	
126	const loyaltyDiscount = discountWhen(LOYALTY_DISCOUNT_RATE, isLoyalCustomer);
127	
128	const followUpDiscount = discountWhen(FOLLOW_UP_DISCOUNT_RATE, isFollowUpQuote);
129	
130	const POLICY_MODIFIERS: PolicyModifier[] = [
131	  cursedSurcharge,
132	  highEnchantmentSurcharge,
133	  firstInsuranceSurcharge,
134	  loyaltyDiscount,
135	  followUpDiscount,
136	];
137	
138	const sumModifiers = (base: number, items: Item[], context: QuoteContext): number =>
139	  POLICY_MODIFIERS.reduce((total, modifier) => total + modifier(base, items, context), 0);
140	
141	const quotePremium = (items: Item[], context: QuoteContext): number => {
142	  const base = totalBasePremiumFor(items);
143	  return Math.ceil(base + sumModifiers(base, items, context) + PROCESSING_FEE);
144	};
145	
146	const insuranceValueFor = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;
147	
148	const insuranceSumOf = (items: Item[]): number =>
149	  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
150	
151	const policyItemsFor = (step: Step, scenario: Scenario): Item[] =>
152	  scenario.steps[step.policy ?? 0].items ?? [];
153	
154	const damagesIn = (step: Step): Damage[] => step.incident?.damages ?? [];
155	
156	const insuredItemFor = (damage: Damage, items: Item[]): Item | undefined =>
157	  items.find((item) => item.type === damage.itemType);
158	
159	const triggersPartialPayout = (item: Item | undefined): boolean =>
160	  (item?.enchantment ?? 0) >= PAYOUT_HIGH_ENCHANTMENT_THRESHOLD;
161	
162	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
163	  triggersPartialPayout(item) ? damage.amount * PAYOUT_HIGH_ENCHANTMENT_RATE : damage.amount;
164	
165	const payoutForDamage = (damage: Damage, items: Item[]): number =>
166	  Math.max(0, reimbursableAmount(damage, insuredItemFor(damage, items)) - DEDUCTIBLE);
167	
168	const totalPayoutFor = (damages: Damage[], items: Item[]): number =>
169	  damages.reduce((total, damage) => total + payoutForDamage(damage, items), 0);
170	
171	const processClaim = (
172	  step: Step,
173	  scenario: Scenario,
174	  alreadyPaid: number,
175	): { result: StepResult; paid: number } => {
176	  const policyItems = policyItemsFor(step, scenario);
177	  const cap = CAP_MULTIPLIER * insuranceSumOf(policyItems);
178	  const desired = totalPayoutFor(damagesIn(step), policyItems);
179	  const payout = Math.min(desired, cap - alreadyPaid);
180	  return { result: { payout, remainingCap: cap - alreadyPaid - payout }, paid: alreadyPaid + payout };
181	};
182	
183	type RunState = { results: StepResult[]; paidByPolicy: Map<number, number> };
184	
185	const processStep = (
186	  state: RunState,
187	  step: Step,
188	  scenario: Scenario,
189	  quoteIndex: number,
190	): RunState => {
191	  if (step.op === "claim") {
192	    const policyIndex = step.policy ?? 0;
193	    const alreadyPaid = state.paidByPolicy.get(policyIndex) ?? 0;
194	    const { result, paid } = processClaim(step, scenario, alreadyPaid);
195	    const paidByPolicy = new Map(state.paidByPolicy);
196	    paidByPolicy.set(policyIndex, paid);
197	    return { results: [...state.results, result], paidByPolicy };
198	  }
199	  const result: StepResult = {
200	    premium: quotePremium(step.items ?? [], { customer: scenario.customer, quoteIndex }),
201	  };
202	  return { results: [...state.results, result], paidByPolicy: state.paidByPolicy };
203	};
204	
205	export const runScenario = (scenario: Scenario): ScenarioResult => {
206	  const initial: RunState = { results: [], paidByPolicy: new Map() };
207	  const final = scenario.steps.reduce(
208	    (state, step, index) => processStep(state, step, scenario, index),
209	    initial,
210	  );
211	  return { results: final.results };
212	};
